import{_ as p,c as r}from"./app.0b00aae6.js";const n={},e=r('<h1 id="_30-\u8BB2-\u5DE5\u6B32\u5584\u5176\u4E8B\u5FC5\u5148\u5229\u5176\u5668-\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u539F\u7406\u4E0E\u884C\u4E1A\u5E38\u7528\u5DE5\u5177\u7B80\u4ECB" tabindex="-1"><a class="header-anchor" href="#_30-\u8BB2-\u5DE5\u6B32\u5584\u5176\u4E8B\u5FC5\u5148\u5229\u5176\u5668-\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u539F\u7406\u4E0E\u884C\u4E1A\u5E38\u7528\u5DE5\u5177\u7B80\u4ECB" aria-hidden="true">#</a> 30 \u8BB2\uFF1A\u5DE5\u6B32\u5584\u5176\u4E8B\u5FC5\u5148\u5229\u5176\u5668\uFF1A\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u539F\u7406\u4E0E\u884C\u4E1A\u5E38\u7528\u5DE5\u5177\u7B80\u4ECB</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\u3002\u4ECA\u5929\u6211\u548C\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u662F\uFF1A\u5DE5\u6B32\u5584\u5176\u4E8B\u5FC5\u5148\u5229\u5176\u5668\u4E4B\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u539F\u7406\u4E0E\u884C\u4E1A\u5E38\u7528\u5DE5\u5177\u7B80\u4ECB\u3002</p><p>\u6211\u5728\u300A\u804A\u804A\u6027\u80FD\u6D4B\u8BD5\u7684\u57FA\u672C\u65B9\u6CD5\u4E0E\u5E94\u7528\u9886\u57DF\u300B\u8FD9\u4E2A\u4E3B\u9898\u91CC\u4ECB\u7ECD\u4E86\u4E03\u79CD\u6D4B\u8BD5\u65B9\u6CD5\uFF0C\u4F46\u4E0D\u7BA1\u662F\u4EC0\u4E48\u7C7B\u578B\u7684\u6027\u80FD\u6D4B\u8BD5\u65B9\u6CD5\uFF0C\u90FD\u9700\u8981\u53BB\u6A21\u62DF\u5927\u91CF\u5E76\u53D1\u7528\u6237\u7684\u540C\u65F6\u6267\u884C\uFF0C\u6240\u4EE5\u6027\u80FD\u6D4B\u8BD5\u57FA\u672C\u90FD\u662F\u9760\u5DE5\u5177\u5B9E\u73B0\u3002\u6CA1\u6709\u5DE5\u5177\uFF0C\u6027\u80FD\u6D4B\u8BD5\u5C06\u5BF8\u6B65\u96BE\u884C\u3002</p><p>\u6240\u4EE5\uFF0C\u6211\u4ECA\u5929\u5C31\u4ECE\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5DE5\u5177\u8BB2\u8D77\uFF0C\u548C\u4F60\u4E00\u8D77\u8BA8\u8BBA\u5B83\u4EEC\u7684\u5B9E\u73B0\u539F\u7406\uFF0C\u4EE5\u53CA\u5982\u4F55\u7528\u4E8E\u540E\u7AEF\u7684\u6027\u80FD\u6D4B\u8BD5\u3002\u53E6\u5916\uFF0C\u6211\u8FD8\u4F1A\u548C\u4F60\u5206\u4EAB\u4E00\u4E9B\u4E2D\u5927\u578B\u4E92\u8054\u7F51\u4F01\u4E1A\u9009\u62E9\u7684\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u3002</p><p>\u7531\u4E8E\u6211\u4ECA\u5929\u8981\u5206\u4EAB\u7684\u77E5\u8BC6\u70B9\u6BD4\u8F83\u591A\uFF0C\u800C\u4E14\u662F\u76F8\u5BF9\u72EC\u7ACB\u7684\uFF0C\u6240\u4EE5\u6211\u4F1A\u91C7\u7528\u95EE\u7B54\u7684\u5F62\u5F0F\u5C55\u5F00\u8FD9\u4E9B\u5185\u5BB9\u3002\u6211\u5E0C\u671B\u901A\u8FC7\u4ECA\u5929\u7684\u5206\u4EAB\uFF0C\u4F60\u80FD\u591F\u5BF9\u4EE5\u4E0B\u7684\u95EE\u9898\u548C\u77E5\u8BC6\u70B9\u6709\u5B8C\u6574\u3001\u6E05\u6670\u7684\u7406\u89E3\u4E0E\u8BA4\u8BC6\uFF1A</p><ul><li>\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u548C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u4E4B\u95F4\u7684\u5173\u7CFB\u662F\u4EC0\u4E48\uFF1F</li><li>\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u548C GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u5DE5\u5177\u6700\u5927\u7684\u533A\u522B\u662F\u4EC0\u4E48\uFF1F</li><li>\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u7684\u539F\u7406\u662F\u4EC0\u4E48\uFF1F</li><li>\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u4E2D\uFF0C\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u8BBE\u8BA1\u662F\u4EC0\u4E48\u610F\u601D\uFF0C\u5177\u4F53\u4F1A\u6D89\u53CA\u54EA\u4E9B\u5185\u5BB9\uFF1F</li><li>\u4E1A\u5185\u4E3B\u6D41\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u6709\u54EA\u4E9B\uFF1F</li></ul><p><strong>\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u548C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u4E4B\u95F4\u7684\u5173\u7CFB\u662F\u4EC0\u4E48\uFF1F</strong></p><p>\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u662F\u5B9E\u73B0\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u6280\u672F\u624B\u6BB5\uFF0C\u4F46\u662F\u5343\u4E07\u4E0D\u8981\u7B80\u5355\u5730\u628A\u4F7F\u7528\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u7B49\u540C\u4E8E\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\uFF0C\u5B83\u53EA\u662F\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u4E2D\u7684\u4E00\u4E2A\u5FC5\u8981\u6B65\u9AA4\u800C\u5DF2\u3002</p><p><strong>\u5B8C\u6574\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5E94\u8BE5\u5305\u62EC\u6027\u80FD\u9700\u6C42\u83B7\u53D6\u3001\u6027\u80FD\u573A\u666F\u8BBE\u8BA1\u3001\u6027\u80FD\u6D4B\u8BD5\u811A\u672C\u5F00\u53D1\u3001\u6027\u80FD\u573A\u666F\u5B9E\u73B0\u3001\u6027\u80FD\u6D4B\u8BD5\u6267\u884C\u3001\u6027\u80FD\u7ED3\u679C\u62A5\u544A\u5206\u6790\u3001\u6027\u80FD\u4F18\u5316\u548C\u518D\u9A8C\u8BC1</strong>\u3002</p><p>\u5728\u8FD9\u5176\u4E2D\uFF0C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u4E3B\u8981\u5728\u6027\u80FD\u6D4B\u8BD5\u811A\u672C\u5F00\u53D1\u3001\u6027\u80FD\u573A\u666F\u5B9E\u73B0\u3001\u6027\u80FD\u6D4B\u8BD5\u6267\u884C\u8FD9\u4E09\u4E2A\u6B65\u9AA4\u4E2D\u53D1\u6325\u4F5C\u7528\uFF0C\u800C\u5176\u4ED6\u73AF\u8282\u90FD\u8981\u4F9D\u9760\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u7684\u4E13\u4E1A\u77E5\u8BC6\u5B8C\u6210\u3002</p><p>\u662F\u4E0D\u662F\u611F\u89C9\u6709\u70B9\u62BD\u8C61\uFF0C\u96BE\u4EE5\u7406\u89E3\u5462\uFF1F\u6211\u6765\u505A\u4E2A\u7C7B\u6BD4\u5427\u3002</p><p>\u5047\u5982\u4F60\u73B0\u5728\u8981\u53BB\u533B\u9662\u770B\u75C5\uFF0C\u533B\u751F\u4F1A\u6839\u636E\u4F60\u5BF9\u8EAB\u4F53\u4E0D\u9002\u7684\u63CF\u8FF0\uFF0C\u8981\u6C42\u4F60\u5148\u53BB\u9A8C\u8840\uFF0C\u5E76\u786E\u5B9A\u9700\u8981\u68C0\u67E5\u7684\u8840\u6DB2\u6307\u6807\u3002\u9A8C\u8840\u662F\u901A\u8FC7\u4E13\u4E1A\u7684\u533B\u7597\u4EEA\u5668\u5206\u6790\u4F60\u7684\u8840\u6837\uFF0C\u5E76\u5F97\u5230\u9A8C\u8840\u62A5\u544A\u3002</p><p>\u533B\u751F\u62FF\u5230\u9A8C\u8840\u62A5\u544A\u540E\uFF0C\u6839\u636E\u5E38\u5E74\u79EF\u7D2F\u7684\u4E13\u4E1A\u77E5\u8BC6\uFF0C\u7136\u540E\u7ED3\u5408\u9A8C\u8840\u62A5\u544A\u7684\u5404\u9879\u6307\u6807\u4EE5\u53CA\u6307\u6807\u4E4B\u95F4\u7684\u76F8\u4E92\u5173\u7CFB\u5224\u65AD\u4F60\u7684\u75C5\u60C5\uFF0C\u5E76\u7ED9\u51FA\u8BCA\u65AD\u7ED3\u679C\u4EE5\u53CA\u76F8\u5E94\u7684\u6CBB\u7597\u63AA\u65BD\u3002</p><p>\u540C\u6837\u7684\u9A8C\u8840\u62A5\u544A\uFF0C\u5982\u679C\u7ED9\u4E0D\u61C2\u533B\u672F\u7684\u4EBA\u770B\uFF0C\u5C31\u662F\u4E00\u5806\u6CA1\u6709\u610F\u4E49\u7684\u6570\u636E\uFF1B\u5982\u679C\u7ED9\u4E00\u4E2A\u521D\u7EA7\u533B\u751F\u770B\uFF0C\u4ED6\u53EF\u80FD\u53EA\u80FD\u57FA\u4E8E\u5355\u4E2A\u6307\u6807\u7684\u9AD8\u4F4E\u7ED9\u51FA\u53EF\u80FD\u7684\u63A8\u6D4B\uFF1B\u4F46\u662F\uFF0C\u5982\u679C\u662F\u7ED9\u4E00\u4E2A\u5177\u6709\u4E30\u5BCC\u4E34\u5E8A\u7ECF\u9A8C\u7684\u533B\u751F\u770B\uFF0C\u4ED6\u5F80\u5F80\u53EF\u4EE5\u6839\u636E\u8FD9\u4E9B\u6307\u6807\u4EE5\u53CA\u5B83\u4EEC\u4E4B\u95F4\u7684\u76F8\u4E92\u5173\u7CFB\u7ED9\u51FA\u5F88\u660E\u786E\u7684\u8BCA\u65AD\u7ED3\u679C\u3002</p><p>\u73B0\u5728\uFF0C\u6211\u628A\u8FD9\u4E2A\u8FC7\u7A0B\u548C\u6027\u80FD\u6D4B\u8BD5\u505A\u4E2A\u7C7B\u6BD4\uFF0C\u628A\u6027\u80FD\u6D4B\u8BD5\u5BF9\u5E94\u5230\u6574\u4E2A\u770B\u75C5\u7684\u8FC7\u7A0B\uFF1A</p><ul><li>\u9700\u6C42\u83B7\u53D6\u5BF9\u5E94\u7684\u662F\u4F60\u5411\u533B\u751F\u63CF\u8FF0\u8EAB\u4F53\u4E0D\u9002\u7EC6\u8282\u7684\u8FC7\u7A0B\uFF0C\u533B\u751F\u9700\u8981\u77E5\u9053\u8981\u5E2E\u4F60\u89E3\u51B3\u4EC0\u4E48\u95EE\u9898\uFF1B</li><li>\u8BBE\u8BA1\u6027\u80FD\u573A\u666F\u5BF9\u5E94\u7684\u662F\u533B\u751F\u51B3\u5B9A\u9700\u8981\u68C0\u67E5\u54EA\u4E9B\u8840\u6DB2\u6307\u6807\u7684\u8FC7\u7A0B\uFF1B</li><li>\u4F7F\u7528\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u5BF9\u5E94\u7684\u662F\u4F7F\u7528\u533B\u7597\u4EEA\u5668\u5206\u6790\u8840\u6837\u7684\u8FC7\u7A0B;</li><li>\u6027\u80FD\u6D4B\u8BD5\u62A5\u544A\u5BF9\u5E94\u7684\u5C31\u662F\u9A8C\u8840\u62A5\u544A;</li><li>\u6027\u80FD\u6D4B\u8BD5\u4EBA\u5458\u5206\u6790\u6027\u80FD\u7ED3\u679C\u62A5\u544A\u7684\u8FC7\u7A0B\uFF0C\u5BF9\u5E94\u7684\u662F\u533B\u751F\u89E3\u8BFB\u9A8C\u8840\u62A5\u544A\u7684\u8FC7\u7A0B\uFF1B</li><li>\u6027\u80FD\u6D4B\u8BD5\u4EBA\u5458\u6839\u636E\u6027\u80FD\u62A5\u544A\u8FDB\u884C\u6027\u80FD\u4F18\u5316\u7684\u8FC7\u7A0B\uFF0C\u5BF9\u5E94\u7684\u662F\u533B\u751F\u6839\u636E\u9A8C\u8840\u62A5\u544A\u5224\u65AD\u4F60\u7684\u75C5\u60C5\uFF0C\u5E76\u7ED9\u51FA\u76F8\u5E94\u6CBB\u7597\u63AA\u65BD\u7684\u8FC7\u7A0B\u3002</li></ul><p>\u6240\u4EE5\uFF0C\u5728\u6211\u770B\u6765<strong>\u4F7F\u7528\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u83B7\u5F97\u6027\u80FD\u6D4B\u8BD5\u62A5\u544A\u53EA\u662F\u6027\u80FD\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\u7684\u4E00\u4E2A\u5FC5\u8981\u6B65\u9AA4\u800C\u5DF2\uFF0C\u800C\u5F97\u51FA\u62A5\u544A\u7684\u76EE\u7684\u662F\u8BA9\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u53BB\u505A\u8FDB\u4E00\u6B65\u7684\u5206\u6790\uFF0C\u4EE5\u5F97\u51FA\u6700\u7EC8\u7ED3\u8BBA\uFF0C\u5E76\u7ED9\u51FA\u6027\u80FD\u4F18\u5316\u7684\u63AA\u65BD</strong>\u3002</p><p><strong>\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u548C GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u5DE5\u5177\u6700\u5927\u7684\u533A\u522B\u662F\u4EC0\u4E48\uFF1F</strong></p><p>\u867D\u7136\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u548C GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u5DE5\u5177\u90FD\u662F\u901A\u8FC7\u81EA\u52A8\u5316\u7684\u624B\u6BB5\u6A21\u62DF\u7EC8\u7AEF\u7528\u6237\u4F7F\u7528\u7CFB\u7EDF\u7684\u884C\u4E3A\uFF0C\u4F46\u662F\u4E24\u8005\u5B9E\u73B0\u7684\u539F\u7406\u622A\u7136\u4E0D\u540C\u3002</p><p><strong>\u7B2C\u4E00\u4E2A\u663E\u8457\u533A\u522B\u662F\uFF0C\u6A21\u62DF\u7528\u6237\u884C\u4E3A\u7684\u65B9\u5F0F</strong>\u3002</p><p>GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u5DE5\u5177\u6A21\u62DF\u7684\u662F\u7528\u6237\u7684\u754C\u9762\u64CD\u4F5C\uFF0C\u56E0\u6B64\u6D4B\u8BD5\u811A\u672C\u8BB0\u5F55\u7684\u662F\u7528\u6237\u5728\u754C\u9762\u4E0A\u5BF9\u63A7\u4EF6\u7684\u64CD\u4F5C\uFF1B\u800C\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u6A21\u62DF\u7684\u662F\u7528\u6237\u7684\u5BA2\u6237\u7AEF\u4E0E\u670D\u52A1\u5668\u4E4B\u95F4\u7684\u901A\u4FE1\u534F\u8BAE\u548C\u6570\u636E\uFF0C\u8FD9\u4E9B\u901A\u4FE1\u534F\u8BAE\u548C\u6570\u636E\u5F80\u5F80\u662F\u7528\u6237\u5728\u754C\u9762\u4E0A\u6267\u884C GUI \u64CD\u4F5C\u65F6\u4EA7\u751F\u7684\u3002</p><p>\u660E\u767D\u4E86\u8FD9\u4E00\u70B9\uFF0C\u4F60\u81EA\u7136\u5C31\u80FD\u660E\u767D\u4E3A\u4EC0\u4E48\u5F55\u5236\u865A\u62DF\u7528\u6237\u6027\u80FD\u6D4B\u8BD5\u811A\u672C\u65F6\uFF0C\u6211\u4EEC\u9700\u8981\u5148\u9009\u5B9A\u5F55\u5236\u534F\u8BAE\u4E86\u3002</p><p>\u53E6\u5916\uFF0C\u6B63\u662F\u7531\u4E8E\u811A\u672C\u7684\u6A21\u62DF\u662F\u57FA\u4E8E\u534F\u8BAE\u7684\uFF0C\u6240\u4EE5\u6211\u4EEC\u624D\u80FD\u6BD4\u8F83\u65B9\u4FBF\u5730\u6A21\u62DF\u6210\u5343\u4E0A\u4E07\u5E76\u53D1\u7528\u6237\u540C\u65F6\u4F7F\u7528\u7CFB\u7EDF\u7684\u573A\u666F\uFF1B\u5426\u5219\uFF0C\u5982\u679C\u6027\u80FD\u6D4B\u8BD5\u57FA\u4E8E GUI \u53D1\u8D77\uFF0C\u90A3\u6211\u4EEC\u5C31\u9700\u8981\u6210\u5343\u4E0A\u4E07\u7684\u6D4F\u89C8\u5668\u540C\u65F6\u6267\u884C\u7528\u4F8B\uFF0C\u800C\u8FD9\u663E\u7136\u662F\u4E0D\u53EF\u80FD\u7684\u3002</p><p><strong>\u7B2C\u4E8C\u4E2A\u663E\u8457\u7684\u533A\u522B\u662F\uFF0C\u6D4B\u8BD5\u7684\u6267\u884C\u65B9\u5F0F</strong>\u3002</p><p>GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u7684\u6267\u884C\uFF0C\u4E00\u822C\u662F\u5355\u7528\u6237\u6267\u884C\u5E76\u9A8C\u8BC1\u529F\u80FD\u7ED3\u679C\uFF1B\u800C\u6027\u80FD\u6D4B\u8BD5\u7684\u6267\u884C\uFF0C\u5F80\u5F80\u9700\u8981\u540C\u65F6\u6A21\u62DF\u5927\u91CF\u7684\u5E76\u53D1\u7528\u6237\uFF0C\u4E0D\u4EC5\u9700\u8981\u9A8C\u8BC1\u4E1A\u52A1\u529F\u80FD\u662F\u5426\u6210\u529F\u5B8C\u6210\uFF0C\u8FD8\u8981\u6536\u96C6\u5404\u79CD\u6027\u80FD\u76D1\u63A7\u6307\u6807\uFF0C\u4F1A\u6D89\u53CA\u5230\u538B\u529B\u4EA7\u751F\u5668\u3001\u5E76\u53D1\u7528\u6237\u8C03\u5EA6\u63A7\u5236\u3001\u5B9E\u65F6\u76D1\u63A7\u6536\u96C6\u7B49\u5185\u5BB9\uFF0C\u6240\u4EE5\u6027\u80FD\u6D4B\u8BD5\u7684\u6267\u884C\u63A7\u5236\u8981\u6BD4 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u590D\u6742\u5F97\u591A\u3002</p><p>\u8FD9\u90E8\u5206\u5185\u5BB9\uFF0C\u6211\u7A0D\u540E\u5728\u7B2C 32 \u548C 33 \u8FD9\u4E24\u7BC7\u6587\u7AE0\u4E2D\u8BE6\u7EC6\u5C55\u5F00\u3002</p><p><strong>\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u7684\u539F\u7406\u662F\u4EC0\u4E48\uFF1F</strong></p><p>\u867D\u7136\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u79CD\u7C7B\u5F88\u591A\uFF0C\u4F46\u662F\u7531\u4E8E\u90FD\u4E0D\u80FD\u901A\u8FC7 GUI \u7684\u65B9\u5F0F\u6765\u6A21\u62DF\u5E76\u53D1\uFF0C\u6240\u4EE5\u5176\u57FA\u672C\u539F\u7406\u548C\u4E3B\u8981\u6982\u5FF5\u57FA\u672C\u4E00\u81F4\u3002</p><p><strong>\u9996\u5148\uFF0C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u4F1A\u57FA\u4E8E\u5BA2\u6237\u7AEF\u4E0E\u670D\u52A1\u5668\u7AEF\u7684\u901A\u4FE1\u534F\u8BAE\uFF0C\u6784\u5EFA\u6A21\u62DF\u4E1A\u52A1\u64CD\u4F5C\u7684\u865A\u62DF\u7528\u6237\u811A\u672C</strong>\u3002\u5BF9\u4E8E\u76EE\u524D\u4E3B\u6D41\u7684 Web \u5E94\u7528\uFF0C\u901A\u5E38\u662F\u57FA\u4E8E HTTP/HTTPS \u534F\u8BAE\uFF1B\u5BF9\u4E8E Web Service \u5E94\u7528\uFF0C\u662F\u57FA\u4E8E Web Service \u534F\u8BAE\uFF1B\u81F3\u4E8E\u5177\u4F53\u57FA\u4E8E\u54EA\u79CD\u534F\u8BAE\uFF0C\u4F60\u9700\u8981\u548C\u5F00\u53D1\u4EBA\u5458\u6216\u8005\u67B6\u6784\u5E08\u786E\u8BA4\uFF0C\u5F53\u7136\u73B0\u5728\u6709\u4E9B\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u4E5F\u53EF\u4EE5\u76F4\u63A5\u5E2E\u4F60\u68C0\u6D4B\u534F\u8BAE\u7684\u79CD\u7C7B\u3002</p><p>\u6211\u4EEC\u628A\u8FD9\u4E9B\u57FA\u4E8E\u534F\u8BAE\u6A21\u62DF\u7528\u6237\u884C\u4E3A\u7684\u811A\u672C\u79F0\u4E3A\u865A\u62DF\u7528\u6237\u811A\u672C\uFF0C\u800C\u628A\u5F00\u53D1\u548C\u4EA7\u751F\u8FD9\u4E9B\u811A\u672C\u7684\u5DE5\u5177\u79F0\u4E3A<strong>\u865A\u62DF\u7528\u6237\u811A\u672C\u751F\u6210\u5668</strong>\u3002</p><p>\u4E0D\u540C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\u751F\u6210\u5668\uFF0C\u5728\u4F7F\u7528\u4E0A\u7684\u533A\u522B\u6BD4\u8F83\u5927\uFF1A\u6BD4\u5982\uFF0CLoadRunner \u662F\u901A\u8FC7\u5F55\u5236\u540E\u518D\u4FEE\u6539\u7684\u65B9\u5F0F\u751F\u6210\u865A\u62DF\u7528\u6237\u811A\u672C\uFF1B\u800C JMeter \u4E3B\u8981\u662F\u901A\u8FC7\u6DFB\u52A0\u5404\u79CD\u7EC4\u4EF6\uFF0C\u7136\u540E\u5BF9\u7EC4\u4EF6\u8FDB\u884C\u914D\u7F6E\u7684\u65B9\u5F0F\u751F\u6210\u865A\u62DF\u7528\u6237\u811A\u672C\u3002</p><p>\u867D\u7136 LoadRunner \u4E5F\u652F\u6301\u91C7\u7528\u76F4\u63A5\u5F00\u53D1\u7684\u65B9\u5F0F\u4EA7\u751F\u865A\u62DF\u7528\u6237\u811A\u672C\uFF0C\u4F46\u662F\u56E0\u4E3A\u5F00\u53D1\u96BE\u5EA6\u592A\u5927\uFF0C\u6240\u4EE5\u57FA\u672C\u4E0A\u90FD\u662F\u91C7\u7528\u5148\u5F55\u5236\u518D\u5F00\u53D1\u7684\u65B9\u5F0F\uFF0C\u4E0D\u4F1A\u76F4\u63A5\u53BB\u5F00\u53D1\u3002\u53E6\u5916\uFF0C\u867D\u7136 JMeter \u4E5F\u652F\u6301\u5F55\u5236\uFF0C\u4F46\u662F JMeter \u7684\u5F55\u5236\u529F\u80FD\u662F\u901A\u8FC7\u8BBE\u7F6E\u4EE3\u7406\u5B8C\u6210\u7684\uFF0C\u800C\u4E14\u5F55\u5236\u51FA\u6765\u7684\u811A\u672C\u90FD\u662F\u539F\u59CB\u7684 http \u8BF7\u6C42\uFF0C\u5E76\u6CA1\u6709\u7ECF\u8FC7\u9002\u5F53\u7684\u5C01\u88C5\uFF0C\u6240\u4EE5\u5F55\u5236\u529F\u80FD\u6BD4\u8F83\u5F31\u3002</p><p>\u867D\u7136\u4E0D\u540C\u5DE5\u5177\u7684\u4F7F\u7528\u65B9\u5F0F\u5404\u6709\u7279\u8272\uFF0C\u4F46\u5176\u672C\u8D28\u4E0A\u90FD\u662F\u901A\u8FC7\u534F\u8BAE\u6A21\u62DF\u7528\u6237\u7684\u884C\u4E3A\u3002</p><p><strong>\u7136\u540E\uFF0C\u5F00\u53D1\u5B8C\u6210\u4E86\u865A\u62DF\u7528\u6237\u811A\u672C\u4E4B\u540E\uFF0C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u4F1A\u4EE5\u591A\u7EBF\u7A0B\u6216\u591A\u8FDB\u7A0B\u7684\u65B9\u5F0F\u5E76\u53D1\u6267\u884C\u865A\u62DF\u7528\u6237\u811A\u672C\uFF0C\u6765\u6A21\u62DF\u5927\u91CF\u5E76\u53D1\u7528\u6237\u7684\u540C\u65F6\u8BBF\u95EE\uFF0C\u4ECE\u800C\u5BF9\u670D\u52A1\u5668\u65BD\u52A0\u6D4B\u8BD5\u8D1F\u8F7D</strong>\u3002</p><p>\u5176\u4E2D\uFF0C\u6211\u4EEC\u628A\u5B9E\u9645\u53D1\u8D77\u6D4B\u8BD5\u8D1F\u8F7D\u7684\u673A\u5668\u79F0\u4E3A<strong>\u538B\u529B\u4EA7\u751F\u5668</strong>\u3002\u53D7\u9650\u4E8E CPU\u3001\u5185\u5B58\uFF0C\u4EE5\u53CA\u7F51\u7EDC\u5E26\u5BBD\u7B49\u786C\u4EF6\u8D44\u6E90\uFF0C\u4E00\u53F0\u538B\u529B\u4EA7\u751F\u5668\u80FD\u591F\u627F\u8F7D\u7684\u865A\u62DF\u7528\u6237\u6570\u91CF\u662F\u6709\u9650\u7684\uFF0C\u5F53\u9700\u8981\u53D1\u8D77\u7684\u5E76\u53D1\u7528\u6237\u6570\u91CF\u8D85\u8FC7\u4E86\u5355\u53F0\u538B\u529B\u4EA7\u751F\u5668\u80FD\u591F\u63D0\u4F9B\u7684\u6781\u9650\u65F6\uFF0C\u5C31\u9700\u8981\u5F15\u5165\u591A\u53F0\u538B\u529B\u4EA7\u751F\u5668\u5408\u4F5C\u53D1\u8D77\u9700\u8981\u7684\u6D4B\u8BD5\u8D1F\u8F7D\u3002</p><p>\u4E00\u65E6\u6709\u4E86\u591A\u53F0\u538B\u529B\u4EA7\u751F\u5668\uFF0C\u90A3\u5C31\u9700\u8981\u4E00\u4E2A\u4E13\u95E8\u7684\u63A7\u5236\u5668\u6765\u7EDF\u4E00\u7BA1\u7406\u4E0E\u534F\u8C03\u8FD9\u4E9B\u538B\u529B\u4EA7\u751F\u5668\uFF0C\u6211\u4EEC\u628A\u8FD9\u4E2A\u4E13\u95E8\u7684\u63A7\u5236\u5668\u79F0\u4E3A<strong>\u538B\u529B\u63A7\u5236\u5668</strong>\u3002\u538B\u529B\u63A7\u5236\u5668\u4F1A\u6839\u636E\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u7684\u8BBE\u8BA1\uFF0C\u6765\u63A7\u5236\u548C\u534F\u8C03\u591A\u53F0\u538B\u529B\u4EA7\u751F\u5668\u4E0A\u7684\u591A\u7EBF\u7A0B\u6216\u591A\u8FDB\u7A0B\u6267\u884C\u7684\u865A\u62DF\u7528\u6237\u811A\u672C\uFF0C\u6700\u7EC8\u6A21\u62DF\u51FA\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u4E2D\u7684\u6D4B\u8BD5\u8D1F\u8F7D\u3002</p><p><strong>\u63A5\u7740\uFF0C\u5728\u65BD\u52A0\u6D4B\u8BD5\u8D1F\u8F7D\u7684\u6574\u4E2A\u8FC7\u7A0B\u4E2D\uFF0C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u9664\u4E86\u9700\u8981\u76D1\u63A7\u548C\u6536\u96C6\u88AB\u6D4B\u7CFB\u7EDF\u7684\u5404\u79CD\u6027\u80FD\u6570\u636E\u4EE5\u5916\uFF0C\u8FD8\u9700\u8981\u76D1\u63A7\u88AB\u6D4B\u7CFB\u7EDF\u5404\u4E2A\u670D\u52A1\u5668\u7684\u5404\u79CD\u8F6F\u786C\u4EF6\u8D44\u6E90</strong>\u3002\u6BD4\u5982\uFF0C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u9700\u8981\u76D1\u63A7\u5E94\u7528\u670D\u52A1\u5668\u3001\u6570\u636E\u5E93\u670D\u52A1\u5668\u3001\u6D88\u606F\u961F\u5217\u670D\u52A1\u5668\u3001\u7F13\u5B58\u670D\u52A1\u5668\u7B49\u5404\u79CD\u8D44\u6E90\u7684\u5360\u7528\u7387\u3002\u6211\u4EEC\u901A\u5E38\u628A\u5B8C\u6210\u76D1\u63A7\u548C\u6570\u636E\u6536\u96C6\u7684\u6A21\u5757\u79F0\u4E3A<strong>\u7CFB\u7EDF\u76D1\u63A7\u5668</strong>\u3002</p><p>\u5728\u6027\u80FD\u6D4B\u8BD5\u6267\u884C\u8FC7\u7A0B\u4E2D\uFF0C\u7CFB\u7EDF\u76D1\u63A7\u5668\u7684\u6570\u636E\u663E\u793A\u754C\u9762\u662F\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u6700\u5BC6\u5207\u5173\u6CE8\u7684\u90E8\u5206\uFF0C\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u4F1A\u6839\u636E\u5B9E\u65F6\u7684\u6570\u636E\u663E\u793A\u6765\u5224\u65AD\u6D4B\u8BD5\u8D1F\u8F7D\u60C5\u51B5\u4E0B\u7684\u7CFB\u7EDF\u5065\u5EB7\u72B6\u51B5\u3002</p><p>\u4E0D\u540C\u7684\u540E\u7AEF\u6D4B\u8BD5\u5DE5\u5177\u4E2D\uFF0C\u7CFB\u7EDF\u76D1\u63A7\u5668\u80FD\u529B\u5DEE\u522B\u4E5F\u6BD4\u8F83\u5927\u3002\u6BD4\u5982\uFF0CLoadRunner \u7684\u7CFB\u7EDF\u76D1\u63A7\u5668\u5C31\u5F88\u5F3A\u5927\uFF0C\u652F\u6301\u6536\u96C6\u5404\u79CD\u64CD\u4F5C\u7CFB\u7EDF\u7684\u7CFB\u7EDF\u53C2\u6570\uFF0C\u8FD8\u652F\u6301\u4E0E SiteScope \u7B49\u7B2C\u4E09\u65B9\u4E13\u4E1A\u76D1\u63A7\u5DE5\u5177\u7684\u65E0\u7F1D\u96C6\u6210\u3002</p><p><strong>\u6700\u540E\uFF0C\u6D4B\u8BD5\u6267\u884C\u5B8C\u6210\u540E\uFF0C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u4F1A\u5C06\u7CFB\u7EDF\u76D1\u63A7\u5668\u6536\u96C6\u7684\u6240\u6709\u4FE1\u606F\u6C47\u603B\u4E3A\u5B8C\u6574\u6D4B\u8BD5\u62A5\u544A</strong>\uFF0C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u901A\u5E38\u80FD\u591F\u57FA\u4E8E\u8BE5\u62A5\u544A\u751F\u6210\u5404\u7C7B\u6307\u6807\u7684\u5404\u79CD\u56FE\u8868\uFF0C\u8FD8\u80FD\u5C06\u591A\u4E2A\u6307\u6807\u5173\u8054\u5728\u4E00\u8D77\u8FDB\u884C\u7EFC\u5408\u5206\u6790\u6765\u627E\u51FA\u5404\u4E2A\u6307\u6807\u4E4B\u95F4\u7684\u5173\u8054\u6027\u3002\u6211\u4EEC\u628A\u5B8C\u6210\u8FD9\u90E8\u5206\u5DE5\u4F5C\u7684\u6A21\u5757\u79F0\u4E3A<strong>\u6D4B\u8BD5\u7ED3\u679C\u5206\u6790\u5668</strong>\u3002</p><p>\u9700\u8981\u5F3A\u8C03\u7684\u662F\uFF0C\u6D4B\u8BD5\u7ED3\u679C\u5206\u6790\u5668\u53EA\u662F\u6309\u9700\u63D0\u4F9B\u591A\u79CD\u4E0D\u540C\u7EF4\u5EA6\u548C\u8868\u73B0\u5F62\u5F0F\u7684\u6570\u636E\u5C55\u73B0\u5DE5\u4F5C\uFF0C\u800C\u5BF9\u6570\u636E\u7684\u5206\u6790\u5DE5\u4F5C\uFF0C\u8FD8\u662F\u8981\u4F9D\u8D56\u4E8E\u5177\u6709\u4E30\u5BCC\u7ECF\u9A8C\u7684\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u3002</p><p><strong>\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u8BBE\u8BA1\u662F\u4EC0\u4E48\u610F\u601D\uFF0C\u5177\u4F53\u4F1A\u6D89\u53CA\u54EA\u4E9B\u5185\u5BB9\uFF1F</strong></p><p>\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u8BBE\u8BA1\uFF0C\u662F\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u4E2D\u7684\u91CD\u8981\u6982\u5FF5\uFF0C\u4E5F\u662F\u538B\u529B\u63A7\u5236\u5668\u53D1\u8D77\u6D4B\u8BD5\u8D1F\u8F7D\u7684\u4F9D\u636E\u3002</p><p>\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u8BBE\u8BA1\uFF0C\u76EE\u7684\u662F\u8981\u63CF\u8FF0\u6027\u80FD\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\u6240\u6709\u4E0E\u6D4B\u8BD5\u8D1F\u8F7D\u4EE5\u53CA\u76D1\u63A7\u76F8\u5173\u7684\u5185\u5BB9\u3002\u901A\u5E38\u6765\u8BB2\uFF0C\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u8BBE\u8BA1\u4E3B\u8981\u4F1A\u6D89\u53CA\u4EE5\u4E0B\u90E8\u5206\uFF1A</p><p>\u5E76\u53D1\u7528\u6237\u6570\u662F\u591A\u5C11\uFF1F \u6D4B\u8BD5\u521A\u5F00\u59CB\u65F6\uFF0C\u4EE5\u4EC0\u4E48\u6837\u7684\u901F\u7387\u6765\u6DFB\u52A0\u5E76\u53D1\u7528\u6237\uFF1F\u6BD4\u5982\uFF0C\u6BCF\u79D2\u589E\u52A0 5 \u4E2A\u5E76\u53D1\u7528\u6237\u3002 \u8FBE\u5230\u6700\u5927\u5E76\u53D1\u7528\u6237\u6570\u540E\u6301\u7EED\u591A\u957F\u65F6\u95F4\uFF1F \u6D4B\u8BD5\u7ED3\u675F\u65F6\uFF0C\u4EE5\u4EC0\u4E48\u6837\u7684\u901F\u7387\u6765\u51CF\u5C11\u5E76\u53D1\u7528\u6237\uFF1F\u6BD4\u5982\uFF0C\u6BCF\u79D2\u51CF\u5C11 5 \u4E2A\u5E76\u53D1\u7528\u6237\u3002 \u9700\u8981\u5305\u542B\u54EA\u4E9B\u4E1A\u52A1\u64CD\u4F5C\uFF0C\u5404\u4E2A\u4E1A\u52A1\u64CD\u4F5C\u7684\u5360\u6BD4\u662F\u591A\u5C11\uFF1F\u6BD4\u5982\uFF0C10%\u7684\u7528\u6237\u5728\u505A\u767B\u5F55\u64CD\u4F5C\uFF0C70%\u7684\u7528\u6237\u5728\u505A\u67E5\u8BE2\u64CD\u4F5C\uFF0C\u5176\u4ED6 20%\u7684\u7528\u6237\u5728\u505A\u8BA2\u5355\u64CD\u4F5C\u3002 \u4E00\u8F6E\u865A\u62DF\u7528\u6237\u811A\u672C\u6267\u884C\u7ED3\u675F\u540E\uFF0C\u9700\u8981\u7B49\u5F85\u591A\u957F\u65F6\u95F4\u5F00\u59CB\u4E0B\u4E00\u6B21\u6267\u884C\uFF1F \u540C\u4E00\u865A\u62DF\u7528\u6237\u811A\u672C\u4E2D\uFF0C\u5404\u4E2A\u64CD\u4F5C\u4E4B\u95F4\u7684\u7B49\u5F85\u65F6\u95F4\u662F\u591A\u5C11\uFF1F \u9700\u8981\u76D1\u63A7\u54EA\u4E9B\u88AB\u6D4B\u670D\u52A1\u5668\u7684\u54EA\u4E9B\u6307\u6807\uFF1F \u811A\u672C\u51FA\u9519\u65F6\u7684\u5904\u7406\u65B9\u5F0F\u662F\u4EC0\u4E48\uFF1F\u6BD4\u5982\uFF0C\u9519\u8BEF\u7387\u8FBE\u5230 10%\u65F6\uFF0C\u81EA\u52A8\u505C\u6B62\u8BE5\u811A\u672C\u3002 \u9700\u8981\u4F7F\u7528\u591A\u5C11\u53F0\u538B\u529B\u4EA7\u751F\u5668\uFF1F \u4EE5\u4E0A\u8FD9\u4E9B\u573A\u666F\u7EC4\u5408\u5728\u4E00\u8D77\uFF0C\u5C31\u6784\u6210\u4E86\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u8BBE\u8BA1\u7684\u4E3B\u8981\u5185\u5BB9\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0C\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u4F1A\u5BF9\u6D4B\u8BD5\u8D1F\u8F7D\u7EC4\u6210\u3001\u8D1F\u8F7D\u7B56\u7565\u3001\u8D44\u6E90\u76D1\u63A7\u8303\u56F4\u5B9A\u4E49\u3001\u7EC8\u6B62\u65B9\u5F0F\uFF0C\u4EE5\u53CA\u8D1F\u8F7D\u4EA7\u751F\u89C4\u5212\u4F5C\u51FA\u5B9A\u4E49\uFF0C\u800C\u5176\u4E2D\u7684\u6BCF\u4E00\u9879\u8FD8\u4F1A\u5305\u542B\u66F4\u591A\u7684\u5185\u5BB9\u3002\u5177\u4F53\u8BF7\u53C2\u89C1\u5982\u56FE 1 \u6240\u793A\u7684\u601D\u7EF4\u5BFC\u56FE\u3002</p><p><img src="https://static001.geekbang.org/resource/image/4f/02/4f4f3d91ba710fe1f39cac341d296402.png" alt="\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u7684\u8BBE\u8BA1"></p><p><strong>\u4E1A\u5185\u4E3B\u6D41\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u6709\u54EA\u4E9B\uFF1F</strong></p><p>\u76EE\u524D\uFF0C\u4E1A\u5185\u6709\u5F88\u591A\u6210\u719F\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\uFF0C\u6BD4\u5982\u4F20\u7EDF\u7684 LoadRunner\u3001JMeter\u3001NeoLoad \u7B49\u3002\u53E6\u5916\uFF0C\u73B0\u5728\u8FD8\u6709\u5F88\u591A\u4E91\u7AEF\u90E8\u7F72\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u6216\u5E73\u53F0\uFF0C\u6BD4\u5982 CloudTest\u3001Loadstorm\u3001\u963F\u91CC\u7684 PTS \u7B49\u3002</p><p>\u5176\u4E2D\uFF0C\u6700\u4E3A\u5E38\u7528\u7684\u5546\u4E1A\u5DE5\u5177\u662F HP \u8F6F\u4EF6\uFF08\u73B0\u5728\u5DF2\u7ECF\u88AB Micro Focus \u6536\u8D2D\uFF09\u7684 LoadRunner\uFF0C\u7531\u4E8E\u5176\u5F3A\u5927\u7684\u529F\u80FD\u548C\u5E7F\u6CDB\u7684\u534F\u8BAE\u652F\u6301\uFF0C\u51E0\u4E4E\u5DF2\u7ECF\u6210\u4E86\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u7684\u4EE3\u540D\u8BCD\u3002\u5927\u91CF\u7684\u4F20\u7EDF\u8F6F\u4EF6\u4F01\u4E1A\uFF0C\u4E5F\u57FA\u672C\u90FD\u4F7F\u7528 LoadRunner \u5B9E\u65BD\u6027\u80FD\u6D4B\u8BD5\uFF0C\u6240\u4EE5\u6211\u5728\u540E\u9762\u5206\u4EAB\u4F01\u4E1A\u7EA7\u670D\u52A1\u5668\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u5B9E\u8DF5\u65F6\uFF0C\u4E5F\u662F\u4EE5 LoadRunner \u4E3A\u57FA\u7840\u5C55\u5F00\u7684\u3002</p><p>\u53E6\u5916\uFF0CJMeter \u662F\u76EE\u524D\u5F00\u6E90\u9886\u57DF\u6700\u4E3B\u6D41\u7684\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u3002JMeter \u7684\u529F\u80FD\u975E\u5E38\u7075\u6D3B\uFF0C\u80FD\u591F\u652F\u6301 HTTP\u3001FTP\u3001\u6570\u636E\u5E93\u7684\u6027\u80FD\u6D4B\u8BD5\uFF0C\u4E5F\u80FD\u591F\u5145\u5F53 HTTP \u4EE3\u7406\u6765\u5F55\u5236\u6D4F\u89C8\u5668\u7684 HTTP \u8BF7\u6C42\uFF0C\u8FD8\u53EF\u4EE5\u6839\u636E Apache \u7B49 Web \u670D\u52A1\u5668\u7684\u65E5\u5FD7\u6587\u4EF6\u56DE\u653E HTTP \u6D41\u91CF\uFF0C\u8FD8\u53EF\u4EE5\u901A\u8FC7\u6269\u5C55\u652F\u6301\u6D77\u91CF\u7684\u5E76\u53D1\u3002</p><p>\u7136\u540E\uFF0C\u518D\u52A0\u4E0A JMeter \u5F00\u6E90\u514D\u8D39\u7684\u7279\u70B9\uFF0C\u5DF2\u7ECF\u88AB\u5F88\u591A\u4E92\u8054\u7F51\u4F01\u4E1A\u5E7F\u6CDB\u5E94\u7528\u3002\u6BD4\u5982\uFF0C\u997F\u4E86\u4E48\u5C31\u662F\u4F7F\u7528 JMeter \u6765\u5B8C\u6210\u7CFB\u7EDF\u7684\u5168\u94FE\u8DEF\u538B\u529B\u6D4B\u8BD5\u3002</p><p>\u5176\u5B9E\uFF0C\u4F20\u7EDF\u8F6F\u4EF6\u4F01\u4E1A\u504F\u5411\u4E8E\u4F7F\u7528 LoadRunner\uFF0C\u800C\u4E92\u8054\u7F51\u4F01\u4E1A\u666E\u904D\u91C7\u7528 JMeter\uFF0C\u662F\u6709\u539F\u56E0\u7684\u3002</p><p>LoadRunner License \u662F\u6309\u7167\u5E76\u53D1\u7528\u6237\u6570\u6536\u8D39\u7684\uFF0C\u5E76\u53D1\u7528\u6237\u6570\u8D8A\u9AD8\u6536\u8D39\u4E5F\u8D8A\u8D35\uFF0C\u4F46\u662F LoadRunner \u7684\u811A\u672C\u5F00\u53D1\u529F\u80FD\u3001\u6267\u884C\u63A7\u5236\u3001\u7CFB\u7EDF\u76D1\u63A7\u4EE5\u53CA\u62A5\u544A\u529F\u80FD\u90FD\u975E\u5E38\u5F3A\u5927\uFF0C\u6613\u5B66\u6613\u7528\u3002</p><p>\u800C\u4F20\u7EDF\u8F6F\u4EF6\u4F01\u4E1A\uFF0C\u9700\u8981\u6D4B\u8BD5\u7684\u5E76\u53D1\u7528\u6237\u6570\u5E76\u4E0D\u4F1A\u592A\u9AD8\uFF0C\u901A\u5E38\u662F\u5728\u51E0\u767E\u5230\u5341\u51E0\u4E07\u8FD9\u4E2A\u6570\u91CF\u7EA7\uFF0C\u800C\u4E14\u5B83\u4EEC\u5F88\u5728\u610F\u8F6F\u4EF6\u7684\u6613\u7528\u6027\u548C\u5B98\u65B9\u652F\u6301\u80FD\u529B\uFF0C\u6240\u4EE5\u5F80\u5F80\u70ED\u8877\u4E8E\u76F4\u63A5\u9009\u62E9\u6210\u719F\u7684\u5546\u4E1A\u5DE5\u5177 LoadRunner\u3002</p><p>\u4F46\u662F\uFF0C\u4E92\u8054\u7F51\u4F01\u4E1A\u7684\u5E76\u53D1\u7528\u6237\u8BF7\u6C42\u6570\u91CF\u5F88\u9AD8\uFF0C\u5F88\u591A\u8F6F\u4EF6\u90FD\u4F1A\u8FBE\u5230\u767E\u4E07\uFF0C\u751A\u81F3\u662F\u5343\u4E07\u7684\u7EA7\u522B\u3002\u90A3\u4E48\uFF0C\u5982\u679C\u4F7F\u7528 LoadRunner \u7684\u8BDD\uFF1A</p><ol><li>\u8D39\u7528\u4F1A\u9AD8\u7684\u79BB\u8C31\uFF1B</li><li>LoadRunner \u5BF9\u6D77\u91CF\u5E76\u53D1\u7684\u6D4B\u8BD5\u652F\u6301\u5E76\u4E0D\u592A\u597D\uFF1B</li><li>\u5F88\u591A\u4E92\u8054\u7F51\u4F01\u4E1A\u8FD8\u4F1A\u6709\u7279\u5B9A\u7684\u5DE5\u5177\u9700\u6C42\uFF0C\u8FD9\u4E9B\u7279\u5B9A\u7684\u9700\u6C42\u5F88\u96BE\u5728 LoadRunner \u4E2D\u5B9E\u73B0\uFF0C\u800C\u5728\u5F00\u6E90\u7684 JMeter \u4E2D\uFF0C\u7528\u6237\u5B8C\u5168\u53EF\u4EE5\u6839\u636E\u9700\u6C42\u8FDB\u884C\u6269\u5C55\u3002</li></ol><p>\u6240\u4EE5\u4E92\u8054\u7F51\u4F01\u4E1A\u5F80\u5F80\u9009\u7528 JMeter \u65B9\u6848\uFF0C\u800C\u4E14\u901A\u5E38\u4F1A\u81EA\u5DF1\u7EF4\u62A4\u6269\u5C55\u7248\u672C\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u4ECA\u5929\uFF0C\u6211\u4EE5\u95EE\u7B54\u7684\u5F62\u5F0F\uFF0C\u548C\u4F60\u5206\u4EAB\u4E86\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u7684\u7406\u8BBA\uFF0C\u4EE5\u53CA\u5DE5\u5177\u4F7F\u7528\u7684\u95EE\u9898\u3002</p><p>\u9996\u5148\uFF0C\u6211\u548C\u4F60\u89E3\u91CA\u4E86\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u548C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u4E4B\u95F4\u7684\u5173\u7CFB\u3002\u5728\u6211\u770B\u6765\u4F7F\u7528\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u83B7\u5F97\u6027\u80FD\u6D4B\u8BD5\u62A5\u544A\uFF0C\u53EA\u662F\u6027\u80FD\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\u7684\u4E00\u4E2A\u5FC5\u8981\u6B65\u9AA4\u800C\u5DF2\uFF0C\u800C\u5F97\u51FA\u62A5\u544A\u7684\u76EE\u7684\u662F\u8BA9\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u53BB\u5206\u6790\u5E76\u7ED9\u51FA\u6027\u80FD\u4F18\u5316\u7684\u63AA\u65BD\u3002</p><p>\u7136\u540E\uFF0C\u6211\u89E3\u91CA\u4E86\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u548C GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u5DE5\u5177\u6700\u5927\u7684\u533A\u522B\uFF0C\u5373\u5B83\u4EEC\u6A21\u62DF\u7528\u6237\u884C\u4E3A\u7684\u65B9\u5F0F\u4EE5\u53CA\u6D4B\u8BD5\u7684\u6267\u884C\u65B9\u5F0F\u4E0D\u540C\u3002</p><p>\u63A5\u7740\uFF0C\u6211\u4ECB\u7ECD\u4E86\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u7684\u57FA\u672C\u539F\u7406\u3002\u5B83\u9996\u5148\u901A\u8FC7\u865A\u62DF\u7528\u6237\u811A\u672C\u751F\u6210\u5668\u751F\u6210\u865A\u62DF\u7528\u6237\u811A\u672C\uFF1B\u7136\u540E\u6839\u636E\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u8BBE\u8BA1\u7684\u8981\u6C42\uFF0C\u901A\u8FC7\u538B\u529B\u63A7\u5236\u5668\u63A7\u5236\u534F\u8C03\u5404\u4E2A\u538B\u529B\u4EA7\u751F\u5668\u4EE5\u5E76\u53D1\u7684\u65B9\u5F0F\u6267\u884C\u865A\u62DF\u7528\u6237\u811A\u672C\uFF1B\u540C\u65F6\uFF0C\u5728\u6D4B\u8BD5\u6267\u884C\u8FC7\u7A0B\u4E2D\uFF0C\u901A\u8FC7\u7CFB\u7EDF\u76D1\u63A7\u5668\u6536\u96C6\u5404\u79CD\u6027\u80FD\u6307\u6807\u4EE5\u53CA\u7CFB\u7EDF\u8D44\u6E90\u5360\u7528\u7387\uFF1B\u6700\u540E\uFF0C\u901A\u8FC7\u6D4B\u8BD5\u7ED3\u679C\u5206\u6790\u5668\u5C55\u793A\u6D4B\u8BD5\u7ED3\u679C\u6570\u636E\u3002</p><p>\u6700\u540E\uFF0C\u6211\u4ECB\u7ECD\u4E86\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u8BBE\u8BA1\uFF0C\u5E76\u5206\u6790\u4E86\u4E1A\u5185\u4E3B\u6D41\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177 LoadRunner \u548C JMeter\uFF0C\u4EE5\u53CA\u4F20\u7EDF\u8F6F\u4EF6\u4F01\u4E1A\u548C\u4E92\u8054\u7F51\u4F01\u4E1A\u5728\u9009\u62E9\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u65F6\u7684\u8003\u91CF\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u9664\u4E86\u6211\u4ECA\u5929\u63D0\u5230\u7684\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u5916\uFF0C\u4F60\u8FD8\u63A5\u89E6\u8FC7\u54EA\u4E9B\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\uFF1F\u8FD9\u4E9B\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u4E2D\u53C8\u6709\u54EA\u4E9B\u597D\u7684\u8BBE\u8BA1\u5462\uFF1F</p>',65);function t(o,s){return e}var i=p(n,[["render",t],["__file","30.html.vue"]]);export{i as default};
